import{_ as d,c as e,o,a2 as a}from"./chunks/framework.CP8b5y1j.js";const s=JSON.parse('{"title":"随便写","description":"","frontmatter":{},"headers":[],"relativePath":"src/frontend/nodejs.md","filePath":"src/frontend/nodejs.md","lastUpdated":1773982724000}'),r={name:"src/frontend/nodejs.md"};function p(c,t,n,h,l,m){return o(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="随便写" tabindex="-1">随便写 <a class="header-anchor" href="#随便写" aria-label="Permalink to &quot;随便写&quot;">​</a></h1><h2 id="spa" tabindex="-1">SPA <a class="header-anchor" href="#spa" aria-label="Permalink to &quot;SPA&quot;">​</a></h2><p>SSR：服务器渲染（HTML CSS JS data都在服务器渲染好了再发送到浏览器） 第一次渲染的时候 SSR是快于SPA 但是当用户量足够多时，CPU负载太大</p><p>SPA ：单页面应用 客户端渲染（CSR） （HTML CSS JS和data分别在两个不同的服务器上 发到浏览器在组装）虽然速度慢 但是解放服务器压力 也可以解耦（前后端分离）</p><h2 id="pnpm" tabindex="-1">pnpm <a class="header-anchor" href="#pnpm" aria-label="Permalink to &quot;pnpm&quot;">​</a></h2><h3 id="依赖安装" tabindex="-1">依赖安装 <a class="header-anchor" href="#依赖安装" aria-label="Permalink to &quot;依赖安装&quot;">​</a></h3><table tabindex="0"><thead><tr><th>npm</th><th>pnpm</th></tr></thead><tbody><tr><td><code>npm install</code></td><td><code>pnpm install</code></td></tr><tr><td><code>npm install pkg</code></td><td><code>pnpm add pkg</code></td></tr><tr><td><code>npm install -D pkg</code></td><td><code>pnpm add -D pkg</code></td></tr><tr><td><code>npm install -g pkg</code></td><td><code>pnpm add -g pkg</code></td></tr><tr><td><code>npm install --save-exact pkg</code></td><td><code>pnpm add --save-exact pkg</code></td></tr><tr><td><code>npm install pkg@1.0.0</code></td><td><code>pnpm add pkg@1.0.0</code></td></tr><tr><td><code>npm ci</code></td><td><code>pnpm install --frozen-lockfile</code></td></tr></tbody></table><hr><h3 id="依赖卸载" tabindex="-1">依赖卸载 <a class="header-anchor" href="#依赖卸载" aria-label="Permalink to &quot;依赖卸载&quot;">​</a></h3><table tabindex="0"><thead><tr><th>npm</th><th>pnpm</th></tr></thead><tbody><tr><td><code>npm uninstall pkg</code></td><td><code>pnpm remove pkg</code></td></tr><tr><td><code>npm uninstall -g pkg</code></td><td><code>pnpm remove -g pkg</code></td></tr></tbody></table><hr><h3 id="依赖更新" tabindex="-1">依赖更新 <a class="header-anchor" href="#依赖更新" aria-label="Permalink to &quot;依赖更新&quot;">​</a></h3><table tabindex="0"><thead><tr><th>npm</th><th>pnpm</th></tr></thead><tbody><tr><td><code>npm update</code></td><td><code>pnpm update</code></td></tr><tr><td><code>npm update pkg</code></td><td><code>pnpm update pkg</code></td></tr><tr><td><code>npm update -g pkg</code></td><td><code>pnpm update -g pkg</code></td></tr><tr><td><code>npm outdated</code></td><td><code>pnpm outdated</code></td></tr></tbody></table><hr><h3 id="脚本执行" tabindex="-1">脚本执行 <a class="header-anchor" href="#脚本执行" aria-label="Permalink to &quot;脚本执行&quot;">​</a></h3><table tabindex="0"><thead><tr><th>npm</th><th>pnpm</th></tr></thead><tbody><tr><td><code>npm run dev</code></td><td><code>pnpm dev</code> 或 <code>pnpm run dev</code></td></tr><tr><td><code>npm run build</code></td><td><code>pnpm build</code> 或 <code>pnpm run build</code></td></tr><tr><td><code>npm run test</code></td><td><code>pnpm test</code> 或 <code>pnpm run test</code></td></tr><tr><td><code>npm start</code></td><td><code>pnpm start</code></td></tr></tbody></table><blockquote><p>pnpm 可以省略 <code>run</code>，直接写脚本名</p></blockquote><hr><h3 id="远程执行" tabindex="-1">远程执行 <a class="header-anchor" href="#远程执行" aria-label="Permalink to &quot;远程执行&quot;">​</a></h3><table tabindex="0"><thead><tr><th>npm</th><th>pnpm</th></tr></thead><tbody><tr><td><code>npx pkg</code></td><td><code>pnpm dlx pkg</code></td></tr><tr><td><code>npm create xxx</code></td><td><code>pnpm create xxx</code></td></tr><tr><td><code>npx create-xxx</code></td><td><code>pnpm create xxx</code></td></tr></tbody></table><hr><h3 id="项目初始化" tabindex="-1">项目初始化 <a class="header-anchor" href="#项目初始化" aria-label="Permalink to &quot;项目初始化&quot;">​</a></h3><table tabindex="0"><thead><tr><th>npm</th><th>pnpm</th></tr></thead><tbody><tr><td><code>npm init</code></td><td><code>pnpm init</code></td></tr><tr><td><code>npm init -y</code></td><td><code>pnpm init</code> （默认即yes）</td></tr></tbody></table><hr><h3 id="查看信息" tabindex="-1">查看信息 <a class="header-anchor" href="#查看信息" aria-label="Permalink to &quot;查看信息&quot;">​</a></h3><table tabindex="0"><thead><tr><th>npm</th><th>pnpm</th></tr></thead><tbody><tr><td><code>npm list</code></td><td><code>pnpm list</code></td></tr><tr><td><code>npm list --depth=0</code></td><td><code>pnpm list --depth=0</code></td></tr><tr><td><code>npm list -g</code></td><td><code>pnpm list -g</code></td></tr><tr><td><code>npm info pkg</code></td><td><code>pnpm info pkg</code></td></tr><tr><td><code>npm view pkg</code></td><td><code>pnpm view pkg</code></td></tr></tbody></table><hr><h3 id="缓存管理" tabindex="-1">缓存管理 <a class="header-anchor" href="#缓存管理" aria-label="Permalink to &quot;缓存管理&quot;">​</a></h3><table tabindex="0"><thead><tr><th>npm</th><th>pnpm</th></tr></thead><tbody><tr><td><code>npm cache clean --force</code></td><td><code>pnpm store prune</code></td></tr><tr><td><code>npm cache verify</code></td><td><code>pnpm store status</code></td></tr><tr><td>——</td><td><code>pnpm store path</code>（查看store路径）</td></tr></tbody></table><hr><h3 id="版本管理" tabindex="-1">版本管理 <a class="header-anchor" href="#版本管理" aria-label="Permalink to &quot;版本管理&quot;">​</a></h3><table tabindex="0"><thead><tr><th>npm</th><th>pnpm</th></tr></thead><tbody><tr><td><code>npm version patch</code></td><td><code>pnpm version patch</code></td></tr><tr><td><code>npm version minor</code></td><td><code>pnpm version minor</code></td></tr><tr><td><code>npm version major</code></td><td><code>pnpm version major</code></td></tr><tr><td><code>npm -v</code></td><td><code>pnpm -v</code></td></tr></tbody></table><hr><h3 id="发布相关" tabindex="-1">发布相关 <a class="header-anchor" href="#发布相关" aria-label="Permalink to &quot;发布相关&quot;">​</a></h3><table tabindex="0"><thead><tr><th>npm</th><th>pnpm</th></tr></thead><tbody><tr><td><code>npm publish</code></td><td><code>pnpm publish</code></td></tr><tr><td><code>npm login</code></td><td><code>pnpm login</code></td></tr><tr><td><code>npm logout</code></td><td><code>pnpm logout</code></td></tr><tr><td><code>npm whoami</code></td><td><code>pnpm whoami</code></td></tr></tbody></table><hr><h3 id="monorepo-workspace" tabindex="-1">Monorepo / Workspace <a class="header-anchor" href="#monorepo-workspace" aria-label="Permalink to &quot;Monorepo / Workspace&quot;">​</a></h3><table tabindex="0"><thead><tr><th>npm</th><th>pnpm</th></tr></thead><tbody><tr><td><code>npm install -w packages/foo</code></td><td><code>pnpm add pkg --filter foo</code></td></tr><tr><td><code>npm run dev -w packages/foo</code></td><td><code>pnpm --filter foo dev</code></td></tr><tr><td>——</td><td><code>pnpm -r run build</code>（递归执行所有包）</td></tr></tbody></table><blockquote><p>pnpm 的 workspace 支持更强大，是 monorepo 首选</p></blockquote><hr><h3 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h3><blockquote><p>90% 的命令只需把 <code>npm</code> 换成 <code>pnpm</code>，主要区别是：</p><ul><li><code>npm install pkg</code> → <code>pnpm add pkg</code></li><li><code>npx</code> → <code>pnpm dlx</code></li><li><code>npm cache clean</code> → <code>pnpm store prune</code></li></ul></blockquote><h2 id="express" tabindex="-1">Express <a class="header-anchor" href="#express" aria-label="Permalink to &quot;Express&quot;">​</a></h2>',43)])])}const b=d(r,[["render",p]]);export{s as __pageData,b as default};
